import{_ as t,o as a,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"57. Community Mental Health Discipline Mix","description":"","frontmatter":{"title":"57. Community Mental Health Discipline Mix","eba":"Mental Health Services 2024-2028","topics":["discipline","union-matters"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/57-community-mental-health-discipline-mix.md","filePath":"ebas/mental-health/common-terms/staffing/57-community-mental-health-discipline-mix.md"}'),o={name:"ebas/mental-health/common-terms/staffing/57-community-mental-health-discipline-mix.md"};function r(l,e,s,m,c,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_57-community-mental-health-discipline-mix" tabindex="-1">57. Community Mental Health Discipline Mix <a class="header-anchor" href="#_57-community-mental-health-discipline-mix" aria-label="Permalink to &quot;57. Community Mental Health Discipline Mix&quot;">​</a></h1><p><strong>57.1</strong> The Parties agree that a multidisciplinary approach in teams, having regard to client needs and the model of care, can provide improved outcomes for clients.</p><p><strong>57.2</strong> Obligation to replace a Nurse with a Nurse</p><p>Subject to 57.4 and 57.5, a position within a community team which at the commencement of the 2020 Agreement was occupied by a Nurse will be replaced with a Nurse.</p><p><strong>57.3</strong> Records Each Employer will maintain a written record of nursing positions within teams subject to <a href="/eba/ebas/mental-health/common-terms/staffing/60-community-workload-management-system-cwms.html">clause 60</a> (CWMS) and <a href="/eba/ebas/mental-health/common-terms/staffing/61-crisis-team-workload-management-system-ctwms.html">clause 61</a> (CTWMS). This record will be made available to the Union/s upon request. Immediately following 30 March and 30 September each year, Employers will provide a copy of the written record in the format agreed by the MHIIC.</p><p><strong>57.4</strong> Patient Safety/Employee workload considerations If following a reasonable recruitment process for a Nurse (in accordance with <a href="/eba/ebas/mental-health/common-terms/staffing/55-recruitment-to-vacant-position.html">clause 55</a>) a suitably qualified nurse is not able to be appointed and the workload of the team and/or client’s safety would be compromised by a further delay in recruitment the Employer may permanently appoint an alternative discipline and notify the local MHICC by writing of the following:</p><p><strong>(a)</strong> The role title</p><p><strong>(b)</strong> The steps that were taken to fill the vacancy</p><p><strong>(c)</strong> The plan to permanently appoint a nurse to an alternative role or upcoming vacancy within community mental health covered by the Agreement and the expected timelines; and</p><p><strong>(d)</strong> The written record at 57.4 will be updated to reflect the outcome of 57.54.</p><p><strong>57.5</strong> Change An Employer may utilise <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> where, instead of following the process at 57.4, they propose to permanently alter the overall discipline mix recorded in accordance with 57.3. In doing so, the Employer must be able to demonstrate the changes in consumer need for the team and how the care needs will be met.</p>',11)])])}const u=t(o,[["render",r]]);export{d as __pageData,u as default};
